def launchTCPServer(ip="192.168.0.10", port=7801):
    from ..protocols.jsonrpc import JSONRPCProtocol
    from ..dispatch import RPCDispatcher
    print("start tcpServer")
    loop = asyncio.get_event_loop()
    print("asyncio.get_event_loop()")
    tcpServer = TCPRPCServer(JSONRPCProtocol(), RPCDispatcher(), ip, port)
    print("tcpServer")
    # loop.create_task(tcpServer.run())
    try:
        print("run_until_complete")
        loop.run_until_complete(tcpServer.run())
    except OSError:
            print('Interrupted')  # This mechanism doesn't work on Unix build.
    finally:
        tcpServer.close()


